// Generate email content
const complaint = $input.all()[0].json;

return {
  to: complaint.reporter_email,
  subject: `Complaint Registered - ${complaint.complaint_token}`,
  body: `
Dear ${complaint.reporter_name},

Your cyber crime complaint has been successfully registered.

Complaint Token: ${complaint.complaint_token}
Submission Date: ${complaint.submission_date}
Incident Type: ${complaint.incident_type}
Nearest Police Station: ${complaint.nearest_police_station}

Please keep this token number safe for tracking your complaint.
You can track your complaint status at: http://your-portal.com/track

The concerned authorities have been notified and will contact you if additional information is required.

Regards,
National Cyber Crime Reporting Division
Ministry of Home Affairs
  `
};

// Prepare SMS for OTP or notification
const complaint = $input.all()[0].json;

return {
  to: complaint.reporter_phone,
  message: `Your complaint ${complaint.complaint_token} has been registered successfully. Visit our portal to track status.`
};

// Notify Police Station
const complaint = $input.all()[0].json;

return {
  to: 'police@station.gov.in',
  subject: `New Cyber Crime Complaint - ${complaint.complaint_token}`,
  body: `
New cyber crime complaint registered:

Complaint Token: ${complaint.complaint_token}
Incident Type: ${complaint.incident_type}
Victim: ${complaint.reporter_name}
Location: ${complaint.city}, ${complaint.state}
Nearest Police Station: ${complaint.nearest_police_station}
Financial Loss: ₹${complaint.financial_loss}
Incident Date: ${complaint.incident_date}

Description:
${complaint.incident_description}

Please login to the portal for full details.
  `
};
